//! Source location tracking.

/// A byte-offset range into source text.
///
/// `start` is inclusive, `end` is exclusive.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct Span {
    /// Inclusive start byte offset.
    pub start: usize,
    /// Exclusive end byte offset.
    pub end: usize,
}

impl Span {
    /// Create a new span. Panics if `start > end`.
    #[must_use]
    pub fn new(start: usize, end: usize) -> Self {
        assert!(start <= end, "Span start ({start}) must be <= end ({end})");
        Self { start, end }
    }

    /// Number of bytes this span covers.
    #[must_use]
    pub fn len(&self) -> usize {
        self.end - self.start
    }

    /// Whether this span covers zero bytes.
    #[must_use]
    pub fn is_empty(&self) -> bool {
        self.start == self.end
    }
}

impl std::fmt::Display for Span {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}..{}", self.start, self.end)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn span_new() {
        let s = Span::new(0, 5);
        assert_eq!(s.start, 0);
        assert_eq!(s.end, 5);
    }

    #[test]
    fn span_len() {
        assert_eq!(Span::new(3, 7).len(), 4);
    }

    #[test]
    fn span_empty() {
        assert!(Span::new(5, 5).is_empty());
        assert!(!Span::new(0, 1).is_empty());
    }

    #[test]
    fn span_display() {
        assert_eq!(Span::new(10, 20).to_string(), "10..20");
    }

    #[test]
    fn span_equality() {
        assert_eq!(Span::new(0, 5), Span::new(0, 5));
        assert_ne!(Span::new(0, 5), Span::new(0, 6));
    }

    #[test]
    #[should_panic(expected = "start")]
    fn span_invalid_panics() {
        Span::new(10, 5);
    }
}

