//! Lexer for MLPL source code.

use mlpl_core::Span;

use crate::error::ParseError;
use crate::token::{Token, TokenKind};

/// Tokenize MLPL source code.
pub fn lex(source: &str) -> Result<Vec<Token>, ParseError> {
    let mut tokens = Vec::new();
    let bytes = source.as_bytes();
    let mut pos = 0;
    let mut prev_was_value = false;

    while pos < bytes.len() {
        let b = bytes[pos];

        // Skip spaces and tabs (not newlines)
        if b == b' ' || b == b'\t' {
            pos += 1;
            continue;
        }

        // Comments
        if b == b'#' {
            while pos < bytes.len() && bytes[pos] != b'\n' {
                pos += 1;
            }
            continue;
        }

        // Newline
        if b == b'\n' {
            tokens.push(Token {
                kind: TokenKind::Newline,
                span: Span::new(pos, pos + 1),
            });
            pos += 1;
            prev_was_value = false;
            continue;
        }

        // Single-char tokens
        if let Some(kind) = single_char_token(b) {
            prev_was_value = matches!(kind, TokenKind::RParen | TokenKind::RBracket);
            tokens.push(Token {
                kind,
                span: Span::new(pos, pos + 1),
            });
            pos += 1;
            continue;
        }

        // Minus: negative number or operator?
        if b == b'-' {
            if !prev_was_value {
                if let Some((tok, end)) = lex_number(bytes, pos) {
                    tokens.push(Token {
                        kind: tok,
                        span: Span::new(pos, end),
                    });
                    pos = end;
                    prev_was_value = true;
                    continue;
                }
            }
            tokens.push(Token {
                kind: TokenKind::Minus,
                span: Span::new(pos, pos + 1),
            });
            pos += 1;
            prev_was_value = false;
            continue;
        }

        // Numbers
        if b.is_ascii_digit() {
            if let Some((tok, end)) = lex_number(bytes, pos) {
                tokens.push(Token {
                    kind: tok,
                    span: Span::new(pos, end),
                });
                pos = end;
                prev_was_value = true;
                continue;
            }
            return Err(ParseError::InvalidNumber {
                span: Span::new(pos, pos + 1),
            });
        }

        // Identifiers
        if b.is_ascii_alphabetic() || b == b'_' {
            let start = pos;
            while pos < bytes.len()
                && (bytes[pos].is_ascii_alphanumeric() || bytes[pos] == b'_')
            {
                pos += 1;
            }
            let name = std::str::from_utf8(&bytes[start..pos]).unwrap().to_owned();
            tokens.push(Token {
                kind: TokenKind::Ident(name),
                span: Span::new(start, pos),
            });
            prev_was_value = true;
            continue;
        }

        // Unknown character
        let ch = source[pos..].chars().next().unwrap();
        return Err(ParseError::UnexpectedCharacter {
            ch,
            span: Span::new(pos, pos + ch.len_utf8()),
        });
    }

    tokens.push(Token {
        kind: TokenKind::Eof,
        span: Span::new(pos, pos),
    });
    Ok(tokens)
}

/// Try to lex a number (integer or float) starting at `pos`.
/// Returns `(TokenKind, end_pos)` on success.
fn lex_number(bytes: &[u8], start: usize) -> Option<(TokenKind, usize)> {
    let mut pos = start;

    // Optional minus sign
    if pos < bytes.len() && bytes[pos] == b'-' {
        pos += 1;
    }

    // Need at least one digit
    if pos >= bytes.len() || !bytes[pos].is_ascii_digit() {
        return None;
    }

    // Consume digits
    while pos < bytes.len() && bytes[pos].is_ascii_digit() {
        pos += 1;
    }

    // Check for decimal point
    if pos < bytes.len() && bytes[pos] == b'.' && pos + 1 < bytes.len() && bytes[pos + 1].is_ascii_digit() {
        pos += 1; // skip dot
        while pos < bytes.len() && bytes[pos].is_ascii_digit() {
            pos += 1;
        }
        let text = std::str::from_utf8(&bytes[start..pos]).unwrap();
        let val: f64 = text.parse().ok()?;
        Some((TokenKind::FloatLit(val), pos))
    } else {
        let text = std::str::from_utf8(&bytes[start..pos]).unwrap();
        let val: i64 = text.parse().ok()?;
        Some((TokenKind::IntLit(val), pos))
    }
}

/// Match a single-char punctuation/operator token (except minus).
fn single_char_token(b: u8) -> Option<TokenKind> {
    match b {
        b'(' => Some(TokenKind::LParen),
        b')' => Some(TokenKind::RParen),
        b'[' => Some(TokenKind::LBracket),
        b']' => Some(TokenKind::RBracket),
        b',' => Some(TokenKind::Comma),
        b'=' => Some(TokenKind::Equals),
        b';' => Some(TokenKind::Semicolon),
        b'+' => Some(TokenKind::Plus),
        b'*' => Some(TokenKind::Star),
        b'/' => Some(TokenKind::Slash),
        _ => None,
    }
}

