/// Errors produced during lexing and parsing.
#[derive(Clone, Debug, PartialEq)]
pub enum ParseError {
    /// An unexpected character was encountered during lexing.
    UnexpectedCharacter {
        /// The character.
        ch: char,
        /// Where it was found.
        span: Span,
    },
