//! Parser: transforms token stream into AST.

use mlpl_core::Span;

use crate::ast::Expr;
use crate::error::ParseError;
use crate::token::{Token, TokenKind};

/// Parse a token stream into a list of expression statements.
pub fn parse(tokens: &[Token]) -> Result<Vec<Expr>, ParseError> {
    let mut parser = Parser::new(tokens);
    parser.parse_program()
}

pub(crate) struct Parser<'a> {
    pub(crate) tokens: &'a [Token],
    pub(crate) pos: usize,
}

impl<'a> Parser<'a> {
    pub(crate) fn new(tokens: &'a [Token]) -> Self {
        Self { tokens, pos: 0 }
    }

    pub(crate) fn parse_program(&mut self) -> Result<Vec<Expr>, ParseError> {
        let mut stmts = Vec::new();
        self.skip_separators();
        while !self.at_eof() {
            stmts.push(self.parse_expr()?);
            self.skip_separators();
        }
        Ok(stmts)
    }

    /// Parse a single expression. For now: atoms only.
    /// Steps 003-004 will extend this with binop and assignment.
    pub(crate) fn parse_expr(&mut self) -> Result<Expr, ParseError> {
        self.parse_atom()
    }

    pub(crate) fn parse_atom(&mut self) -> Result<Expr, ParseError> {
        let tok = &self.tokens[self.pos];
        match &tok.kind {
            TokenKind::IntLit(n) => {
                let expr = Expr::IntLit(*n, tok.span);
                self.pos += 1;
                Ok(expr)
            }
            TokenKind::FloatLit(f) => {
                let expr = Expr::FloatLit(*f, tok.span);
                self.pos += 1;
                Ok(expr)
            }
            TokenKind::Ident(name) => {
                let expr = Expr::Ident(name.clone(), tok.span);
                self.pos += 1;
                Ok(expr)
            }
            TokenKind::LBracket => self.parse_array_lit(),
            TokenKind::LParen => self.parse_paren(),
            _ => Err(ParseError::UnexpectedToken {
                found: format!("{:?}", tok.kind),
                span: tok.span,
            }),
        }
    }
}

// -- Array and paren parsing --

impl Parser<'_> {
    fn parse_array_lit(&mut self) -> Result<Expr, ParseError> {
        let open_span = self.tokens[self.pos].span;
        self.pos += 1; // skip '['
        let mut elems = Vec::new();
        if !self.check(&TokenKind::RBracket) {
            elems.push(self.parse_expr()?);
            while self.check(&TokenKind::Comma) {
                self.pos += 1; // skip ','
                elems.push(self.parse_expr()?);
            }
        }
        if !self.check(&TokenKind::RBracket) {
            return Err(ParseError::UnclosedDelimiter {
                open: "[".into(),
                span: open_span,
            });
        }
        let close_span = self.tokens[self.pos].span;
        self.pos += 1; // skip ']'
        Ok(Expr::ArrayLit(
            elems,
            Span::new(open_span.start, close_span.end),
        ))
    }

    fn parse_paren(&mut self) -> Result<Expr, ParseError> {
        let open_span = self.tokens[self.pos].span;
        self.pos += 1; // skip '('
        let expr = self.parse_expr()?;
        if !self.check(&TokenKind::RParen) {
            return Err(ParseError::UnclosedDelimiter {
                open: "(".into(),
                span: open_span,
            });
        }
        self.pos += 1; // skip ')'
        Ok(expr)
    }
}

